using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.DragDrop{    /// <summary>    /// 拖放服务    /// </summary>    public class DragDropService    {        private readonly DragDropManager _dragDropManager;                /// <summary>        /// 拖放管理器        /// </summary>        public DragDropManager DragDropManager => _dragDropManager;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public DragDropService(DesignContext context)        {            _dragDropManager = new DragDropManager(context);        }                /// <summary>        /// 初始化拖放服务        /// </summary>        /// <param name="panel">设计面板</param>        public void Initialize(ICSharpCode.WpfDesign.Designer.IDesignPanel panel)        {            _dragDropManager.Initialize(panel);        }    }}